solutions.cpp:
void solve(vector<int>& operations) {
    stack<int> s;
    for (int op : operations) {
        if (op > 0) {
            s.push(op);
        } else if (op < 0) {
            if (!s.empty()) {
                s.pop();
            }
        } else {
            // do nothing
        }
    }
    vector<int> result;
    while (!s.empty()) {
        result.push_back(s.top());
        s.pop();
    }
    reverse(result.begin(), result.end());
    for (int x : result) {
        cout << x << ' ';
    }
}
